import { isCustomColorPalette } from '../../../core/types/color-palette.js';
import { isColoredRangeArray } from '../../../core/types/colored-range.js';
import { getValidColor } from '../../../core/utils/getValidColor.js';
import { isValidColorPalette } from '../../../core/utils/is-valid-color-palette.js';
import { isFunction } from '../../types/guards.js';
import type {
  XYShapeColorPaletteProp,
  XYShapeColorProp,
} from '../../types/xy-chart-props.js';
import type { XYChartData } from '../../types/xy-chart.js';

export function getColorSelection(
  colorProp: XYShapeColorProp | undefined,
  datum: XYChartData,
) {
  if (typeof colorProp === 'string') {
    return { Default: getValidColor(colorProp) };
  }
  if (isFunction(colorProp)) {
    return { Default: colorProp(datum) };
  }

  return undefined;
}

export function getColorPaletteSelection(
  colorProp: XYShapeColorPaletteProp | undefined,
  datum: XYChartData,
) {
  if (isFunction<XYChartData, XYShapeColorPaletteProp>(colorProp)) {
    return colorProp(datum);
  }
  if (
    (colorProp && isCustomColorPalette(colorProp)) ||
    isColoredRangeArray(colorProp) ||
    isValidColorPalette(colorProp)
  ) {
    return colorProp;
  }
  return undefined;
}
